$(document).ready(function(){highlight.initHighlightingOnLoad(),$("body").on("click",".contact-send",function(e){e.preventDefault(),console.log($(this).parent("form").serialize()),$.ajax({url:Routing.generate("homepage"),method:"POST",data:$(this).parent("form").serialize()}).always(function(e){console.log(e),e.success?new Noty({type:"success",theme:"relax",text:"Votre message à bien été envoyé",timeout:2e3}).show():new Noty({type:"error",theme:"relax",text:"Une erreur est survenue",timeout:2e3}).show(),$("form").html(e.view)})})});